export async function fetchFriends(): Promise<Friend[]> {
  const supabase = await getSupabaseServerClientOptional();
  if (!supabase) return [];
  const { data } = await supabase.from("friends").select("*").order("created_at", { ascending: true });
  return (data as any) ?? [];
}

export async function fetchFriendLinks(friendId: string): Promise<FriendSocialLink[]> {
  const supabase = await getSupabaseServerClientOptional();
  if (!supabase) return [];
  const { data } = await supabase
    .from("friend_social_links")
    .select("*")
    .eq("friend_id", friendId)
    .order("position");
  return (data as any) ?? [];
}

