export async function fetchMessages(): Promise<Message[]> {
  const supabase = await getSupabaseServerClientOptional();
  if (!supabase) return [];
  const { data } = await supabase
    .from("messages")
    .select("*")
    .order("created_at", { ascending: false });
  return (data as any) ?? [];
}
